    @Override // com.genoma.plus.dao.citas.CarneCitasDAO
    public List<CarneCitasDTO> buscarCitas(String xAnno, String xIdUsuario) {
        BeanPropertyRowMapper bprm = new BeanPropertyRowMapper(CarneCitasDTO.class);
        String xSql = "(SELECT\n  c_clasecita.Nbre AS ClaseCita,\n  CONCAT(\n    `g_persona`.`Apellido1`,\n    _latin1 ' ',\n    `g_persona`.`Apellido2`,\n    _latin1 ' ',\n    `g_persona`.`Nombre1`,\n    _latin1 ' ',\n    `g_persona`.`Nombre2`\n  ) AS Profesional,\n  \n   g_especialidad.Nbre AS Especialidad,\n  c_citas.Fecha_Cita,\n  c_citas.HoraInicial,\n  c_citas.HoraFinal,\n  c_citas.Asistida,\n  IF(c_citas.Id_MotivoDesistida>1,'Cancelada','Activa') Id_MotivoDesistida,\n  c_citas.Id_Usuario,\n  `g_persona`.`Id` AS idPersona,\n  `g_especialidad`.`Id` AS idEspecialidad,\n  c_citas.Id AS IdCita,\n  `g_sedes`.`Nbre` AS Sede,\n  IFNULL(c_desistidas.`Detalle`, '') AS Detalle,\n  1 AS TipoCita\nFROM\n  c_clasecita\n  INNER JOIN c_citas\n    ON (\n      c_citas.Id_ClaseCita = c_clasecita.Id\n    )\n  INNER JOIN g_especialidad\n    ON (\n      c_clasecita.Id_Especialidad = g_especialidad.Id\n      AND c_citas.Id_Especialidad = `g_especialidad`.`Id`\n    ) -- INNER JOIN w_profesional\n   INNER JOIN `g_persona`\n    ON (\n      c_citas.Id_Profesional = `g_persona`.`Id`\n    )\n  INNER JOIN `g_sedes`\n    ON (\n      `c_citas`.`Id_Sede` = `g_sedes`.`Id`\n    )\n  LEFT JOIN `c_desistidas`\n    ON (\n      `c_citas`.`Id` = `c_desistidas`.`Id`\n    )\n    AND (`tipo` = 1)\nWHERE (\n    c_citas.Id_Usuario = '" + xIdUsuario + "'  AND YEAR(c_citas.Fecha_Cita) = '" + xAnno + "'\n  )\nORDER BY c_citas.Fecha_Cita DESC)\nUNION\n(SELECT\n  c_clasecita.Nbre AS ClaseCita,\n  CONCAT(\n    `g_persona`.`Apellido1`,\n    _latin1 ' ',\n    `g_persona`.`Apellido2`,\n    _latin1 ' ',\n    `g_persona`.`Nombre1`,\n    _latin1 ' ',\n    `g_persona`.`Nombre2`\n  ) AS Profesional,\n  -- w_profesional.NProfesional AS Profesional,\n   g_especialidad.Nbre AS Especialidad,\n  c_citasnp.Fecha_Cita,\n  c_citasnp.HoraInicial,\n  c_citasnp.HoraInicial AS HoraFinal,\n  c_citasnp.Asistida,\n if(c_citasnp.Id_MotivoDesistida>1,'Cancelada','Activa') Id_MotivoDesistida,\n  `c_citasnp`.`Id_Usuario`,\n  `g_persona`.`Id` AS idPersona,\n  `g_especialidad`.`Id` AS idEspecialidad,\n  c_citasnp.Id AS IdCita,\n  g_sedes.`Nbre` AS Sede,\n  IFNULL(c_desistidas.`Detalle`, '') AS Detalle,\n  0 AS TipoCita\nFROM\n  c_clasecita\n  INNER JOIN `c_citasnp`\n    ON (\n      c_citasnp.Id_ClaseCita = c_clasecita.Id\n    )\n  INNER JOIN g_especialidad\n    ON (\n      c_clasecita.Id_Especialidad = g_especialidad.Id\n      AND c_citasnp.Id_Especialidad = `g_especialidad`.`Id`\n    ) \n   INNER JOIN `g_persona`\n    ON (\n      c_citasnp.`Id_Profesional` = `g_persona`.`Id`\n    )\n  INNER JOIN `g_sedes`\n    ON (\n      `c_citasnp`.`Id_Sede` = `g_sedes`.`Id`\n    )\n  LEFT JOIN `c_desistidas`\n    ON (\n      `c_citasnp`.`Id` = `c_desistidas`.`Id`\n    )\n    AND (`tipo` = 2)\nWHERE (c_citasnp.Id_Usuario = '" + xIdUsuario + " ' AND YEAR(c_citasnp.Fecha_Cita) = '" + xAnno + "')\nORDER BY c_citasnp.Fecha_Cita DESC)\nORDER BY Fecha_Cita DESC";
        System.out.println(xSql);
        List<CarneCitasDTO> list = this.jdbcTemplate.query(xSql, bprm);
        return list;
    }

    @Override // com.genoma.plus.dao.citas.CarneCitasDAO
    public List<CarneCitasDTO> buscarCitas(String xAnno, String xIdUsuario, String xidEspecialidad, List<Integer> filtro) {
        BeanPropertyRowMapper bprm = new BeanPropertyRowMapper(CarneCitasDTO.class);
        String xSql = "(SELECT\n  c_clasecita.Nbre AS ClaseCita,\n  CONCAT(\n    `g_persona`.`Apellido1`,\n    _latin1 ' ',\n    `g_persona`.`Apellido2`,\n    _latin1 ' ',\n    `g_persona`.`Nombre1`,\n    _latin1 ' ',\n    `g_persona`.`Nombre2`\n  ) AS Profesional,\n  \n   g_especialidad.Nbre AS Especialidad,\n  c_citas.Fecha_Cita,\n  c_citas.HoraInicial,\n  c_citas.HoraFinal,\n  c_citas.Asistida,\n  IF(c_citas.Id_MotivoDesistida>1,'Cancelada','Activa') Id_MotivoDesistida,\n  c_citas.Id_Usuario,\n  `g_persona`.`Id` AS idPersona,\n  `g_especialidad`.`Id` AS idEspecialidad,\n  c_citas.Id AS IdCita,\n  `g_sedes`.`Nbre` AS Sede,\n  IFNULL(c_desistidas.`Detalle`, '') AS Detalle,\n  1 AS TipoCita\nFROM\n  c_citas \n  INNER JOIN c_clasecita\n    ON (\n      c_citas.Id_ClaseCita = c_clasecita.Id\n    )\n  INNER JOIN g_especialidad\n    ON (\n    c_citas.Id_Especialidad = `g_especialidad`.`Id`\n    ) -- INNER JOIN w_profesional\n   INNER JOIN `g_persona`\n    ON (\n      c_citas.Id_Profesional = `g_persona`.`Id`\n    )\n  INNER JOIN `g_sedes`\n    ON (\n      `c_citas`.`Id_Sede` = `g_sedes`.`Id`\n    )\n  LEFT JOIN `c_desistidas`\n    ON (\n      `c_citas`.`Id` = `c_desistidas`.`Id`\n    )\n    AND (`tipo` = 1)\nWHERE (\n   c_citas.Estado in(" + filtro + ") and c_citas.Id_Usuario = '" + xIdUsuario + "'  AND YEAR(c_citas.Fecha_Cita) = '" + xAnno + "' AND `g_especialidad`.`Id` = '" + xidEspecialidad + "' \n  )\nORDER BY c_citas.Fecha_Cita DESC)\nUNION\n(SELECT\n  c_clasecita.Nbre AS ClaseCita,\n  CONCAT(\n    `g_persona`.`Apellido1`,\n    _latin1 ' ',\n    `g_persona`.`Apellido2`,\n    _latin1 ' ',\n    `g_persona`.`Nombre1`,\n    _latin1 ' ',\n    `g_persona`.`Nombre2`\n  ) AS Profesional,\n  -- w_profesional.NProfesional AS Profesional,\n   g_especialidad.Nbre AS Especialidad,\n  c_citasnp.Fecha_Cita,\n  c_citasnp.HoraInicial,\n  c_citasnp.HoraInicial AS HoraFinal,\n  c_citasnp.Asistida,\n  IF(c_citasnp.Id_MotivoDesistida>1,'Cancelada','Activa') Id_MotivoDesistida,\n  `c_citasnp`.`Id_Usuario`,\n  `g_persona`.`Id` AS idPersona,\n  `g_especialidad`.`Id` AS idEspecialidad,\n  c_citasnp.Id AS IdCita,\n  g_sedes.`Nbre` AS Sede,\n  IFNULL(c_desistidas.`Detalle`, '') AS Detalle,\n  0 AS TipoCita\nFROM\n  c_clasecita\n  INNER JOIN `c_citasnp`\n    ON (\n      c_citasnp.Id_ClaseCita = c_clasecita.Id\n    )\n  INNER JOIN g_especialidad\n    ON (\n      c_clasecita.Id_Especialidad = g_especialidad.Id\n      AND c_citasnp.Id_Especialidad = `g_especialidad`.`Id`\n    ) \n   INNER JOIN `g_persona`\n    ON (\n      c_citasnp.`Id_Profesional` = `g_persona`.`Id`\n    )\n  INNER JOIN `g_sedes`\n    ON (\n      `c_citasnp`.`Id_Sede` = `g_sedes`.`Id`\n    )\n  LEFT JOIN `c_desistidas`\n    ON (\n      `c_citasnp`.`Id` = `c_desistidas`.`Id`\n    )\n    AND (`tipo` = 2)\nWHERE (c_citasnp.Estado in(" + filtro + ") and c_citasnp.Id_Usuario = '" + xIdUsuario + " ' AND YEAR(c_citasnp.Fecha_Cita) = '" + xAnno + "' AND `g_especialidad`.`Id` = '" + xidEspecialidad + "')\nORDER BY c_citasnp.Fecha_Cita DESC)\nORDER BY Fecha_Cita DESC";
        List<CarneCitasDTO> list = this.jdbcTemplate.query(xSql, bprm);
        return list;
    }
